script:
frappe.ui.form.on("Employee Claim", {
  claim_type(frm) {
    const needs_receipt = ["Medical", "Travel"].includes(frm.doc.claim_type);
    frm.toggle_display("receipt", needs_receipt);
    if (!needs_receipt) {
      frm.set_value("receipt", "");
    }
  },
  refresh(frm) {
    frm.trigger("claim_type");
  }
});
